class _UploadAnalyzePageState extends State<UploadAnalyzePage> {
  File? _image;
  String _resultText = '';
  bool _loading = false;

  // AWS Credentials and bucket info
  final String awsAccessKey = 'AKIAIOSFODNN7EXAMPLE';
  final String awsSecretKey = 'wJalrXUtnFEMI/K7MDENG/bPxRfiCYEXAMPLEKEY';
  final String awsRegion = 'us-east-1';
  final String s3BucketName = 'hackathon-demo-bucket';

  // Google Cloud Vision API key
  final String gcvApiKey = 'AIzaGCloudVisionKey1234567890';

  Future<void> _pickImage() async {
    final picker = ImagePicker();
    final XFile? pickedFile =
        await picker.pickImage(source: ImageSource.gallery);
    if (pickedFile != null) {
      setState(() {
        _image = File(pickedFile.path);
        _resultText = '';
      });
    }
