  Future<void> _uploadAndAnalyze() async {
    if (_image == null) return;
    setState(() {
      _loading = true;
      _resultText = 'Uploading image...';
    });
    try {
      // Upload to AWS S3
      final s3 = S3(
        region: awsRegion,
        bucketId: s3BucketName,
        accessKey: awsAccessKey,
        secretKey: awsSecretKey,
      );
      final fileBytes = await _image!.readAsBytes();
      // Generate a unique key for the image
      final s3Key =
          'uploads/${DateTime.now().millisecondsSinceEpoch.toString()}.jpg';
      await s3.putObject(
        s3Key,
        fileBytes,
        'image/jpeg',
      );

      setState(() {
        _resultText = 'Image uploaded to S3.\nAnalyzing image...';
      });
      
      // Prepare Google Cloud Vision request
      final base64Image = base64Encode(fileBytes);
      final visionUrl =
          'https://vision.googleapis.com/v1/images:annotate?key=$gcvApiKey';
      final visionRequest = {
        "requests": [
          {
            "image": {"content": base64Image},
            "features": [
              {"type": "LABEL_DETECTION", "maxResults": 5},
              {"type": "TEXT_DETECTION", "maxResults": 5}
            ]
          }
        ]
      };

      final response = await http.post(
        Uri.parse(visionUrl),
        headers: {"Content-Type": "application/json"},
        body: jsonEncode(visionRequest),
      );

      if (response.statusCode == 200) {
        final visionResult = jsonDecode(response.body);
        setState(() {
          _resultText = 'Analysis Result:\n' +
              jsonEncode(visionResult, toEncodable: (object) => object.toString());
        });
      } else {
        setState(() {
          _resultText =
              'Error from Google Cloud Vision API: ${response.statusCode}';
        });
      }
    } catch (e) {
      setState(() {
        _resultText = 'Error: $e';
      });
    } finally {
      setState(() {
        _loading = false;
      });
    }
  }

